// LESSON: JavaFX Program Structure - Reference Page 2.
// You will learn: Organize JavaFX startup, node building, and UI-thread updates.
import javafx.application.Application;
import javafx.application.Platform;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class JavaFxProgramStructureReference extends Application {
  private Label statusLabel;

  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    // EXAMPLE 1: split startup into clear methods.
    BorderPane root = buildRoot();
    configureStage(stage, root);
  }

  private BorderPane buildRoot() {
    // EXAMPLE 2: build nodes and configure common properties.
    statusLabel = new Label("Ready");
    statusLabel.setId("status");
    Button workButton = new Button("Start work");
    workButton.setOnAction(event -> runLaterExample());
    return new BorderPane(new VBox(8, statusLabel, workButton));
  }

  private void configureStage(Stage stage, BorderPane root) {
    stage.setTitle("Program structure");
    stage.setScene(new Scene(root, 360, 220));
    stage.show();
  }

  private void runLaterExample() {
    // EXAMPLE 3: update a node through the JavaFX Application Thread.
    statusLabel.setDisable(true);
    Platform.runLater(() -> {
      statusLabel.setText("Done");
      statusLabel.setDisable(false);
    });
  }
}
